import { Children, type ReactElement, type ReactNode } from 'react';
import { isElement } from 'react-is';

import Colors from '@dynatrace/strato-design-tokens/colors';

import {
  calculateRangeMarkerCoordinates,
  calculateValueMarkerCoordinates,
} from './calculate-expand-marker-coordinates.js';
import { isSlot } from '../../../../../core/utils/is-slot.js';
import {
  getColorByContrast,
  getColorTokenDefaultValue,
} from '../../../utils/color-contrast.js';
import { getTokenComputedStyle } from '../../../utils/getTokenComputedStyle.js';
import { MarkerAtom } from '../slots/MarkerAtom.js';
import { TrackAtom } from '../slots/TrackAtom.js';
import {
  MarkerEventHandlersMap,
  TrackEventHandlersMap,
} from '../types/event-handlers.js';
import { MarkerCoords, MarkersCoordsPerTrack } from '../types/marker-coords.js';
import { MarkerAtomProps } from '../types/marker.js';
import { TrackAtomProps } from '../types/track.js';

export function aggregateMarkersCoords(
  children: ReactNode,
  trackWidth: number,
) {
  const markersPerTrack: MarkersCoordsPerTrack[] = [];

  const markerEventHandlers: MarkerEventHandlersMap = {};
  const trackEventHandlers: TrackEventHandlersMap = {};

  const tracksConfig: (TrackAtomProps & { markers: MarkerAtomProps[] })[] = [];
  const icons: Array<[ReactElement, string]> = [];

  Children.forEach(children, (track, trackIndex) => {
    if (isSlot(track, TrackAtom)) {
      markersPerTrack[trackIndex] = [];

      trackEventHandlers[trackIndex] = {
        onMouseEnter: track.props.onMouseEnter,
      };

      const markersByTrackConfig: MarkerAtomProps[] = [];
      Children.forEach(track.props.children, (marker) => {
        if (isSlot(marker, MarkerAtom)) {
          let markerAtomCoords: MarkerCoords;
          markersByTrackConfig.push(marker.props);

          const { textOverflow, content, x, width } = marker.props;

          if (marker.props.width === 0) {
            markerAtomCoords = calculateValueMarkerCoordinates(
              content,
              x,
              trackWidth,
            );
          } else {
            markerAtomCoords = calculateRangeMarkerCoordinates(
              content,
              x,
              width,
              trackWidth,
              textOverflow,
            );
          }

          markerEventHandlers[`${trackIndex}_${markerAtomCoords.join('_')}`] = {
            onMouseEnter: marker.props.onMouseEnter,
            onMouseMove: marker.props.onMouseMove,
            onMouseLeave: marker.props.onMouseLeave,
            onClick: marker.props.onClick,
          };

          markersPerTrack[trackIndex].push(markerAtomCoords);
          if (isElement(marker.props.content)) {
            const markerColor = getTokenComputedStyle(marker.props.color);
            const lightTextColor = getColorTokenDefaultValue(
              Colors.Text.Neutral.OnAccent.Default,
            );
            const darkTextColor = getColorTokenDefaultValue(
              Colors.Text.Neutral.Default,
            );
            const contrastTextColor = getColorByContrast(
              markerColor,
              lightTextColor,
              darkTextColor,
            );

            icons.push([marker.props.content, contrastTextColor]);
          }
        }
      });

      tracksConfig.push({ ...track.props, markers: markersByTrackConfig });
    }
  });

  return {
    markersPerTrack,
    markerEventHandlers,
    trackEventHandlers,
    icons,
    tracksConfig,
  };
}
